import { describe, test, expect } from "vitest";

import {
  widenGeneratedTypes,
  applyWidening,
  computeRootExclusion,
  computeRequestOnlyComponentNames,
  verifyNoSharedEnumBearingSchemas,
  verifyWideningHappened,
} from "../../scripts/widen-response-enums.mjs";
import type {
  StrictSchemaNode,
  StrictOpenApiOperation,
  StrictOpenApiSpecFragment,
} from "./strict-fixture-types";

function enumFile(name: string, members: string[]) {
  const body = members.map((m) => `  ${m}: '${m}',`).join("\n");
  return [
    "/**",
    " * Generated by orval",
    " */",
    "",
    `export type ${name} = typeof ${name}[keyof typeof ${name}];`,
    "",
    "",
    "// eslint-disable-next-line @typescript-eslint/no-redeclare",
    `export const ${name} = {`,
    body,
    "} as const;",
    "",
  ].join("\n");
}

describe("widenGeneratedTypes", () => {
  test("widens a component-schema (response) enum, leaves a *Body and a *Params enum closed", () => {
    const files = new Map([
      // Response entity Device.deviceClass — mirrors the real deviceDeviceClass.ts shape.
      [
        "device.ts",
        [
          "import type { DeviceDeviceClass } from './deviceDeviceClass';",
          "",
          "export interface Device {",
          "  deviceClass?: DeviceDeviceClass;",
          "}",
          "",
        ].join("\n"),
      ],
      [
        "deviceDeviceClass.ts",
        enumFile("DeviceDeviceClass", [
          "device",
          "printer",
          "rmmnetworkdevice",
        ]),
      ],

      // An anonymous request body's own hoisted enum field.
      [
        "createWidgetBody.ts",
        [
          "import type { CreateWidgetBodyStatus } from './createWidgetBodyStatus';",
          "",
          "export interface CreateWidgetBody {",
          "  status?: CreateWidgetBodyStatus;",
          "}",
          "",
        ].join("\n"),
      ],
      [
        "createWidgetBodyStatus.ts",
        enumFile("CreateWidgetBodyStatus", ["active", "inactive"]),
      ],

      // A query-parameter type's own hoisted enum field.
      [
        "listWidgetsParams.ts",
        [
          "import type { ListWidgetsOrder } from './listWidgetsOrder';",
          "",
          "export type ListWidgetsParams = {",
          "  order?: ListWidgetsOrder;",
          "};",
          "",
        ].join("\n"),
      ],
      ["listWidgetsOrder.ts", enumFile("ListWidgetsOrder", ["asc", "desc"])],
    ]);

    const widened = widenGeneratedTypes(files, new Set());

    expect(widened.get("deviceDeviceClass.ts")).toContain(
      "export type DeviceDeviceClass = typeof DeviceDeviceClass[keyof typeof DeviceDeviceClass] | (string & {});",
    );
    expect(widened.get("createWidgetBodyStatus.ts")).toBe(
      files.get("createWidgetBodyStatus.ts"),
    );
    expect(widened.get("listWidgetsOrder.ts")).toBe(
      files.get("listWidgetsOrder.ts"),
    );
    // Non-enum files pass through untouched.
    expect(widened.get("device.ts")).toBe(files.get("device.ts"));

    // Second pass over the widened output is a no-op (idempotent).
    const secondPass = widenGeneratedTypes(widened, new Set());
    for (const [fileName, content] of widened) {
      expect(secondPass.get(fileName)).toBe(content);
    }
  });

  test("excludes a named-component request-only root (and its hoisted children) via the spec-derived set, not a suffix", () => {
    const files = new Map([
      [
        "warranty.ts",
        [
          "import type { WarrantyLevel } from './warrantyLevel';",
          "",
          "export interface Warranty {",
          "  level?: WarrantyLevel;",
          "}",
          "",
        ].join("\n"),
      ],
      ["warrantyLevel.ts", enumFile("WarrantyLevel", ["bronze", "gold"])],
    ]);

    // `Warranty` carries no Body/Params/etc. suffix, so only the spec-derived request-only set
    // (computed from requestBody-vs-response reachability — see the next describe block) can
    // correctly identify it as request-side.
    const withoutSpecKnowledge = widenGeneratedTypes(files, new Set());
    expect(withoutSpecKnowledge.get("warrantyLevel.ts")).toContain(
      "| (string & {})",
    );

    const withSpecKnowledge = widenGeneratedTypes(files, new Set(["Warranty"]));
    expect(withSpecKnowledge.get("warrantyLevel.ts")).toBe(
      files.get("warrantyLevel.ts"),
    );
  });
});

describe("applyWidening", () => {
  test("totalMatchCount stays > 0 when re-applied to already-widened content (a re-run over already-widened output is a legitimate no-op, not a silent widening failure)", () => {
    const files = new Map([
      ["deviceDeviceClass.ts", enumFile("DeviceDeviceClass", ["device", "printer"])],
    ]);
    const primaryNamesByFile = new Map([
      ["deviceDeviceClass.ts", new Set(["DeviceDeviceClass"])],
    ]);

    const first = applyWidening(files, primaryNamesByFile, new Set());
    expect(first.totalMatchCount).toBe(1);
    expect(first.files.get("deviceDeviceClass.ts")).toContain("| (string & {})");

    // Simulate a second `main()` invocation over the already-widened file (e.g. no
    // `output.clean: true` regeneration in between): the match count must stay > 0, not drop to
    // 0, so `verifyWideningHappened`'s post-condition doesn't mistake this legitimate idempotent
    // no-op for the widening mechanism silently failing to engage (engineer-r2-f1).
    const second = applyWidening(first.files, primaryNamesByFile, new Set());
    expect(second.totalMatchCount).toBe(1);
    expect(second.files.get("deviceDeviceClass.ts")).toBe(
      first.files.get("deviceDeviceClass.ts"),
    );
  });

  test("totalMatchCount is 0 for a file excluded from widening (a request-side enum)", () => {
    const files = new Map([
      ["warrantyLevel.ts", enumFile("WarrantyLevel", ["bronze", "gold"])],
    ]);
    const primaryNamesByFile = new Map([
      ["warrantyLevel.ts", new Set(["WarrantyLevel"])],
    ]);

    const { totalMatchCount, files: result } = applyWidening(
      files,
      primaryNamesByFile,
      new Set(["WarrantyLevel"]),
    );

    expect(totalMatchCount).toBe(0);
    expect(result.get("warrantyLevel.ts")).toBe(files.get("warrantyLevel.ts"));
  });
});

describe("computeRootExclusion", () => {
  test("matchedRequestOnlyNames stays empty when a request-only name fails to resolve, independent of the ever-present *Params suffix roots", () => {
    // A realistic run always has at least one `*Params` file (Orval emits one per operation), so
    // `rootExcludedNames` is never empty — but that must not mask a genuine failure of the
    // spec-derived request-only name to resolve to any declared type (architect-r2-f2).
    const files = new Map([
      [
        "listWidgetsParams.ts",
        ["export type ListWidgetsParams = {", "  order?: string;", "};", ""].join(
          "\n",
        ),
      ],
    ]);

    const { rootExcludedNames, matchedRequestOnlyNames } = computeRootExclusion(
      files,
      new Set(["Warranty"]),
    );

    expect(rootExcludedNames.size).toBeGreaterThan(0);
    expect(matchedRequestOnlyNames.size).toBe(0);
  });

  test("matchedRequestOnlyNames includes a request-only name that resolves to a declared type, alongside unrelated suffix roots", () => {
    const files = new Map([
      [
        "listWidgetsParams.ts",
        ["export type ListWidgetsParams = {", "  order?: string;", "};", ""].join(
          "\n",
        ),
      ],
      [
        "warranty.ts",
        ["export interface Warranty {", "  level?: string;", "}", ""].join("\n"),
      ],
    ]);

    const { matchedRequestOnlyNames } = computeRootExclusion(
      files,
      new Set(["Warranty"]),
    );

    expect(matchedRequestOnlyNames).toEqual(new Set(["Warranty"]));
  });
});

describe("computeRequestOnlyComponentNames", () => {
  function specWith({
    requestRef,
    alsoInResponse,
    contentType = "application/json",
  }: {
    requestRef: string;
    alsoInResponse: boolean;
    contentType?: string;
  }) {
    return {
      paths: {
        "/write-only": {
          post: {
            requestBody: {
              content: {
                [contentType]: {
                  schema: { $ref: `#/components/schemas/${requestRef}` },
                },
              },
            },
            responses: {
              "200": {
                content: { "application/json": { schema: { type: "object" } } },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
        ...(alsoInResponse
          ? {
              "/read-only": {
                get: {
                  responses: {
                    "200": {
                      content: {
                        [contentType]: {
                          schema: {
                            $ref: `#/components/schemas/${requestRef}`,
                          },
                        },
                      },
                    },
                  },
                } satisfies StrictOpenApiOperation,
              },
            }
          : {}),
      },
      components: {
        schemas: {
          [requestRef]: { type: "object", properties: {} } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;
  }

  test("includes a component reachable only from a requestBody", () => {
    const spec = specWith({ requestRef: "Warranty", alsoInResponse: false });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(
      new Set(["Warranty"]),
    );
  });

  test("excludes a component reachable from both a requestBody and a response", () => {
    const spec = specWith({ requestRef: "Udf", alsoInResponse: true });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(new Set());
  });

  test("PascalCases a spec schema name containing spaces to match Orval's generated type name", () => {
    const spec = specWith({
      requestRef: "Variable Creation Request",
      alsoInResponse: false,
    });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(
      new Set(["VariableCreationRequest"]),
    );
  });

  test("excludes a component reachable from both a requestBody and a response delivered only via '*/*' (not just application/json)", () => {
    // architect-r2-f1: the real spec genuinely uses '*/*' for some response bodies; the
    // reachability walker must consider every content type, not just application/json, or a
    // response-only-via-'*/*' component would be misclassified as request-only.
    const spec = specWith({
      requestRef: "Udf",
      alsoInResponse: true,
      contentType: "*/*",
    });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(new Set());
  });
});

describe("verifyNoSharedEnumBearingSchemas", () => {
  test("throws when a requestBody directly $refs an enum-bearing schema also used in a response", () => {
    const spec = {
      paths: {
        "/proxy": {
          post: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/ProxySettings" },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
        "/site": {
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: { $ref: "#/components/schemas/ProxySettings" },
                  },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
      },
      components: {
        schemas: {
          ProxySettings: {
            type: "object",
            properties: { type: { type: "string", enum: ["http", "socks4"] } },
          } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /ProxySettings/,
    );
    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /POST \/proxy/,
    );
    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(/GET \/site/);
  });

  test("throws when a requestBody reaches an enum-bearing schema only transitively (nested property $ref)", () => {
    const spec = {
      paths: {
        "/site": {
          put: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/CreateSiteRequest" },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: { $ref: "#/components/schemas/ProxySettings" },
                  },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
      },
      components: {
        schemas: {
          CreateSiteRequest: {
            type: "object",
            properties: {
              proxySettings: { $ref: "#/components/schemas/ProxySettings" },
            },
          } satisfies StrictSchemaNode,
          ProxySettings: {
            type: "object",
            properties: { type: { type: "string", enum: ["http", "socks4"] } },
          } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /ProxySettings/,
    );
  });

  test("throws when a response's enum-bearing schema is delivered only via '*/*' content type", () => {
    // architect-r2-f1 regression: the shared-schema guard must consider every content type, not
    // just application/json, since the real spec genuinely uses '*/*' for some responses.
    const spec = {
      paths: {
        "/proxy": {
          post: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/ProxySettings" },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
        "/site": {
          get: {
            responses: {
              "200": {
                content: {
                  "*/*": {
                    schema: { $ref: "#/components/schemas/ProxySettings" },
                  },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
      },
      components: {
        schemas: {
          ProxySettings: {
            type: "object",
            properties: { type: { type: "string", enum: ["http", "socks4"] } },
          } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /ProxySettings/,
    );
  });

  test("does not throw when a shared component is enum-free", () => {
    const spec = {
      paths: {
        "/quickjob": {
          put: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/JobComponentVariable" },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
        "/job": {
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: {
                      $ref: "#/components/schemas/JobComponentVariable",
                    },
                  },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
      },
      components: {
        schemas: {
          JobComponentVariable: {
            type: "object",
            properties: { name: { type: "string" }, value: { type: "string" } },
          } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).not.toThrow();
  });
});

describe("verifyWideningHappened", () => {
  const specWithResponseEnum = {
    paths: {
      "/device/{id}": {
        get: {
          responses: {
            "200": {
              content: {
                "application/json": { schema: { $ref: "#/components/schemas/Device" } },
              },
            },
          },
        } satisfies StrictOpenApiOperation,
      },
    },
    components: {
      schemas: {
        Device: {
          type: "object",
          properties: { deviceClass: { type: "string", enum: ["device", "printer"] } },
        } satisfies StrictSchemaNode,
      },
    },
  } satisfies StrictOpenApiSpecFragment;

  test("throws when the spec has a response-reachable enum-bearing schema but 0 enum-alias declarations were widened", () => {
    expect(() =>
      verifyWideningHappened(specWithResponseEnum, new Set(), new Set(), 0),
    ).toThrow(/0 enum-alias declarations were widened/);
  });

  test("does not throw when at least one enum-alias declaration was widened for a spec with a response enum", () => {
    expect(() =>
      verifyWideningHappened(specWithResponseEnum, new Set(), new Set(), 1),
    ).not.toThrow();
  });

  test("does not throw for a spec with no response-reachable enum at all, even if the widened match count is 0", () => {
    const specWithoutEnum = {
      paths: {
        "/device/{id}": {
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": { schema: { $ref: "#/components/schemas/Device" } },
                },
              },
            },
          } satisfies StrictOpenApiOperation,
        },
      },
      components: {
        schemas: {
          Device: { type: "object", properties: { name: { type: "string" } } } satisfies StrictSchemaNode,
        },
      },
    } satisfies StrictOpenApiSpecFragment;

    expect(() =>
      verifyWideningHappened(specWithoutEnum, new Set(), new Set(), 0),
    ).not.toThrow();
  });

  test("throws when the spec has request-only components but none resolved to a matched declared name", () => {
    expect(() =>
      verifyWideningHappened(
        specWithResponseEnum,
        new Set(["Warranty"]),
        new Set(),
        1,
      ),
    ).toThrow(/Warranty/);
  });

  test("does not throw when the spec's request-only components resolved to at least one matched name", () => {
    expect(() =>
      verifyWideningHappened(
        specWithResponseEnum,
        new Set(["Warranty"]),
        new Set(["Warranty"]),
        1,
      ),
    ).not.toThrow();
  });
});
